// Contexte d'authentification global
// Gère l'état de l'utilisateur connecté dans toute l'application
import React, { createContext, useContext, useState, useEffect } from 'react';
import axios from 'axios';

// Création du contexte
const AuthContext = createContext(null);

// URL de base de l'API backend
const API = 'http://localhost:8000';

export function AuthProvider({ children }) {
  // État utilisateur : null = non connecté
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  // Au démarrage, vérifier si un token existe dans localStorage
  useEffect(() => {
    const token = localStorage.getItem('awal_token');
    const savedUser = localStorage.getItem('awal_user');
    if (token && savedUser) {
      setUser(JSON.parse(savedUser));
      // Ajouter le token dans tous les futurs appels axios
      axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    }
    setLoading(false);
  }, []);

  // ── Inscription ──
  const register = async (name, email, password) => {
    const res = await axios.post(`${API}/auth/register`, { name, email, password });
    const { token, user: u } = res.data;
    localStorage.setItem('awal_token', token);
    localStorage.setItem('awal_user', JSON.stringify(u));
    axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    setUser(u);
    return u;
  };

  // ── Connexion ──
  const login = async (email, password) => {
    const res = await axios.post(`${API}/auth/login`, { email, password });
    const { token, user: u } = res.data;
    localStorage.setItem('awal_token', token);
    localStorage.setItem('awal_user', JSON.stringify(u));
    axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
    setUser(u);
    return u;
  };

  // ── Déconnexion ──
  const logout = () => {
    localStorage.removeItem('awal_token');
    localStorage.removeItem('awal_user');
    delete axios.defaults.headers.common['Authorization'];
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, loading, login, register, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

// Hook personnalisé pour utiliser le contexte
export function useAuth() {
  return useContext(AuthContext);
}
